import React, { useEffect, useState } from "react";
import axios from "axios";
import { useAuth } from "../context/AuthContext";

export default function TelaLogs() {
  const { user } = useAuth();
  const [logs, setLogs] = useState([]);
  const [carregando, setCarregando] = useState(true);
  const [erro, setErro] = useState(null);

  useEffect(() => {
    const fetchLogs = async () => {
      setCarregando(true);
      setErro(null);
      try {
        const res = await axios.get("/api/logs", {
          headers: { Authorization: `Bearer ${user.token}` }
        });
        setLogs(res.data);
      } catch (err) {
        setErro("Erro ao carregar logs");
      } finally {
        setCarregando(false);
      }
    };
    fetchLogs();
  }, [user.token]);

  if (carregando) return <p>Carregando auditoria...</p>;
  if (erro) return <p className="text-red-600">{erro}</p>;

  return (
    <div className="max-w-5xl mx-auto mt-8">
      <h2 className="text-2xl font-bold mb-6">Auditoria do Sistema</h2>
      <div className="overflow-x-auto">
        <table className="min-w-full bg-white border rounded shadow">
          <thead>
            <tr className="bg-gray-100">
              <th className="px-4 py-2 text-left">Data/Hora</th>
              <th className="px-4 py-2 text-left">Usuário</th>
              <th className="px-4 py-2 text-left">Ação</th>
              <th className="px-4 py-2 text-left">Entidade</th>
              <th className="px-4 py-2 text-left">ID</th>
              <th className="px-4 py-2 text-left">Detalhes</th>
            </tr>
          </thead>
          <tbody>
            {logs.map((log) => (
              <tr key={log.id} className="border-t hover:bg-gray-50">
                <td className="px-4 py-2 whitespace-nowrap">{new Date(log.criado_em).toLocaleString()}</td>
                <td className="px-4 py-2">{log.usuario_nome}</td>
                <td className="px-4 py-2 capitalize">{log.acao}</td>
                <td className="px-4 py-2">{log.entidade}</td>
                <td className="px-4 py-2">{log.entidade_id}</td>
                <td className="px-4 py-2 text-xs break-all">
                  {log.detalhes && log.detalhes !== "{}"
                    ? <pre className="whitespace-pre-wrap">{JSON.stringify(JSON.parse(log.detalhes), null, 2)}</pre>
                    : "-"}
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>
      {logs.length === 0 && <div className="text-center py-10 text-gray-500">Nenhum log encontrado.</div>}
    </div>
  );
}
